﻿@inherits LayoutComponentBase
@inject sv_155ece1501934a8198219d403e82d1a3.Services.WizardState Wizard
@implements IDisposable

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Wizard.CurrentStep >= 1 && Wizard.CurrentStep <= WizardState.TotalSteps)
            {
                <div class="wizard-progress">
                    <span>Step @Wizard.CurrentStep of @WizardState.TotalSteps</span>
                    <div class="step-indicators">
                        @for (int i = 1; i <= WizardState.TotalSteps; i++)
                        {
                            var step = i;
                            <span class="step-dot @(Wizard.CompletedSteps.Contains(step) ? "completed" : "") @(Wizard.CurrentStep == step ? "active" : "")"></span>
                        }
                    </div>
                </div>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

