@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_155ece1501934a8198219d403e82d1a3.Services.WizardState Wizard
@inject NavigationManager Nav

<h3>Step 1: Personal Information</h3>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label>Name</label>
        <InputText @bind-Value="Wizard.Name" class="form-control" />
    </div>
    <div class="mb-3">
        <label>Email</label>
        <InputText @bind-Value="Wizard.Email" class="form-control" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(1);
    }

    private void Next()
    {
        Wizard.CompleteStep(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_155ece1501934a8198219d403e82d1a3.Services.WizardState Wizard
@inject NavigationManager Nav

<h3>Step 2: Experience</h3>

@for (int i = 0; i < Wizard.Experience.Count; i++)
{
    var index = i;
    <div class="card mb-2 p-3">
        <div class="mb-2">
            <label>Company</label>
            <InputText @bind-Value="Wizard.Experience[index].Company" class="form-control" />
        </div>
        <div class="mb-2">
            <label>Title</label>
            <InputText @bind-Value="Wizard.Experience[index].Title" class="form-control" />
        </div>
        <div class="mb-2">
            <label>Duration</label>
            <InputText @bind-Value="Wizard.Experience[index].Duration" class="form-control" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add job</button>

<div>
    <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(2);
        if (Wizard.Experience.Count == 0)
            Wizard.Experience.Add(new());
    }

    private void AddEntry() => Wizard.Experience.Add(new());

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.CompleteStep(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject sv_155ece1501934a8198219d403e82d1a3.Services.WizardState Wizard
@inject NavigationManager Nav

<h3>Step 3: References</h3>

@for (int i = 0; i < Wizard.References.Count; i++)
{
    var index = i;
    <div class="card mb-2 p-3">
        <div class="mb-2">
            <label>Name</label>
            <InputText @bind-Value="Wizard.References[index].Name" class="form-control" />
        </div>
        <div class="mb-2">
            <label>Relationship</label>
            <InputText @bind-Value="Wizard.References[index].Relationship" class="form-control" />
        </div>
        <div class="mb-2">
            <label>Phone</label>
            <InputText @bind-Value="Wizard.References[index].Phone" class="form-control" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add reference</button>

<div>
    <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(3);
        if (Wizard.References.Count == 0)
            Wizard.References.Add(new());
    }

    private void AddRef() => Wizard.References.Add(new());

    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        Wizard.CompleteStep(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inject sv_155ece1501934a8198219d403e82d1a3.Services.WizardState Wizard

<h3>Step 4: Review Your Application</h3>

<div class="card p-3 mb-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @Wizard.Name</p>
    <p><strong>Email:</strong> @Wizard.Email</p>
</div>

<div class="card p-3 mb-3">
    <h5>Experience</h5>
    @foreach (var job in Wizard.Experience)
    {
        <p>@job.Title at @job.Company (@job.Duration)</p>
    }
</div>

<div class="card p-3 mb-3">
    <h5>References</h5>
    @foreach (var r in Wizard.References)
    {
        <p>@r.Name — @r.Relationship — @r.Phone</p>
    }
</div>

<button class="btn btn-success" @onclick="Submit">Submit Application</button>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(4);
    }

    private void Submit()
    {
        Wizard.CompleteStep(4);
        // TODO: persist to database
    }
}

